  1	import * as React from 'react';
  2	import { useKialiTranslation } from '../../utils/I18nUtils';
  3	import { Button, ButtonVariant, Spinner, Tooltip, TooltipPosition } from '@patternfly/react-core';
  4	import AceEditor from 'react-ace';
  5	import { Theme } from '../../types/Common';
  6	import { istioAceEditorStyle } from '../../styles/AceEditorStyle';
  7	import { aceOptions, yamlDumpOptions } from '../../types/IstioConfigDetails';
  8	import { getKialiTheme } from '../../utils/ThemeUtils';
  9	import { dump, loadAll, YAMLException } from 'js-yaml';
 10	import ReactAce from 'react-ace/lib/ace';
 11	import { ValidationTypes } from 'types/IstioObjects';
 12	import { kialiStyle } from '../../styles/StyleUtils';
 13	import { Validation } from '../Validations/Validation';
 14	import * as API from '../../services/Api';
 15	
 16	type CheckerTracingConfigProps = {
 17	  configData?: unknown;
 18	};
 19	
 20	const healthStatusStyle = kialiStyle({
 21	  marginLeft: '0.5rem'
 22	});
 23	
 24	export const CheckerTracingConfig: React.FC<CheckerTracingConfigProps> = (props: CheckerTracingConfigProps) => {
 25	  const { t } = useKialiTranslation();
 26	  const [loading, setLoading] = React.useState(false);
 27	  const [error, setError] = React.useState<string | null>(null);
 28	  const [isModified, setIsModified] = React.useState(false);
 29	  const aceEditorRef = React.useRef<ReactAce | null>(null);
 30	  const [source, setSource] = React.useState<string>(dump(props.configData, yamlDumpOptions));
 31	
 32	  const theme = getKialiTheme();
 33	  const [configResult, setConfigResult] = React.useState<string | null>(null);
 34	
 35	  const parseYamlDocumentsSync = (yamlText: string): any => {
 36	    let document: any;
 37	    try {
 38	      loadAll(yamlText, doc => {
 39	        document = doc;
 40	      });
 41	    } catch (e) {
 42	      if (e instanceof YAMLException) {
 43	        setLoading(false);
 44	        setError(e.message);
 45	      }
 46	    }
 47	    return document;
 48	  };
 49	
 50	  const checkConfig = (): void => {
 51	    const objectModified = parseYamlDocumentsSync(source);
 52	    if (!objectModified) {
 53	      return;
 54	    }
 55	    setLoading(true);
 56	    const jsonPatch = JSON.stringify(objectModified).replace(new RegExp('(,null)+]', 'g'), ']');
 57	    API.checkTracingConfig(jsonPatch)
 58	      .then(response => {
 59	        setLoading(false);
 60	        setIsModified(false);
 61	        if (response.data.error) {
 62	          setError(response.data.error);
 63	        } else {
 64	          setConfigResult(response.data.message);
 65	          setError(null);
 66	        }
 67	      })
 68	      .catch(err => {
 69	        setLoading(false);
 70	        setError(err.response?.data?.error);
 71	      });
 72	  };
 73	
 74	  const showResult = (): React.ReactElement => {
 75	    let healthSeverity: ValidationTypes;
 76	
 77	    if (error) {
 78	      healthSeverity = ValidationTypes.Error;
 79	    } else {
 80	      healthSeverity = ValidationTypes.Correct;
 81	    }
 82	
 83	    return (
 84	      <Tooltip
 85	        aria-label={t('Health status')}
 86	        position={TooltipPosition.right}
 87	        enableFlip={true}
 88	        content={<>{error ? error : t('Configuration returned valid results')}</>}
 89	      >
 90	        <span className={healthStatusStyle}>
 91	          <Validation severity={healthSeverity} />
 92	        </span>
 93	      </Tooltip>
 94	    );
 95	  };
 96	
 97	  const handleCheckConfig = (): void => {
 98	    checkConfig();
 99	  };
100	
101	  const onEditorChange = (value: string): void => {
102	    setSource(value);
103	    setIsModified(true);
104	    setError(null);
105	  };
106	
107	  return (
108	    <div style={{ display: 'flex', flexDirection: 'column', height: '600px', paddingTop: '1em' }}>
109	      <div style={{ flexGrow: 1, overflowY: 'auto' }}>
110	        <span>{t('external_services.tracing configuration:')}</span>
111	        <AceEditor
112	          name="ace-editor-tester"
113	          ref={aceEditorRef}
114	          mode="yaml"
115	          theme={theme === Theme.DARK ? 'twilight' : 'eclipse'}
116	          onChange={onEditorChange}
117	          width="100%"
118	          className={istioAceEditorStyle}
119	          height="95%"
120	          wrapEnabled={true}
121	          readOnly={false}
122	          setOptions={aceOptions}
123	          value={source}
124	        />
125	      </div>
126	      <div>
127	        <Button
128	          style={{ marginTop: '10px', marginRight: '5px' }}
129	          variant={ButtonVariant.secondary}
130	          onClick={handleCheckConfig}
131	          isDisabled={loading || !isModified}
132	        >
133	          {t('Test Configuration')}
134	        </Button>
135	        {loading && <Spinner size="sm" />}
136	        {(configResult && !isModified) || error ? showResult() : ''}
137	      </div>
138	    </div>
139	  );
140	};

